import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 寶珠 } from '../bujian/sanmaya.js';
import { 與願印, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛寶 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        // 尊右臂：肘收，前臂橫入胸側，掌仰承珠
        骨(() => { 上臂常勢(筆, -1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.2], [-6.9, 41.9], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        // 仰掌：淺盂之形（掌緣兩弧，指列微露於珠後）
        衣(() => {
            M(-10.4, 41.6);
            Qk(-8.3, 42.6, -6.2, 41.9);
            S();
            M(-10.1, 42.3);
            Qk(-8.3, 43.1, -6.6, 42.5);
            S();
            細(() => {
                for (const t of [0, 1, 2]) {
                    M(-9.9 + t * 1.15, 41.35 - t * 0.12);
                    Qk(-9.6 + t * 1.15, 41.0 - t * 0.12, -9.2 + t * 1.15, 40.85 - t * 0.12);
                    S();
                }
            });
        });
        寶珠(bi, -8.5, 39.1, 0.72, 1.9, 5);
        // 尊左臂：外伸而下，掌與願（現図之勢：臂出體側，掌開向前）
        骨(() => 陰(() => {
            M(13.4, 28.6);
            {
                const C = 筆.C;
                C(14.5, 30.6, 15.1, 33.4, 15.0, 36.2);
            }
            Qk(14.9, 38.0, 14.4, 39.8);
            S();
            M(10.9, 32.6);
            {
                const C = 筆.C;
                C(11.3, 34.6, 11.6, 36.4, 11.6, 38.2);
            }
            S();
        }));
        骨(() => 陰(() => 前臂(bi, 筆, [14.3, 39.9], [16.1, 45.4], { 寬根: 2.4, 寬梢: 1.7, 弓: -0.3, 肘帽: true })));
        與願印(bi, 16.9, 49.2, 0.74, false);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.2, 14.7, 33.6);
        細(() => {
            腕釧(bi, [[-11.4, 40.6, -10.6, 41.5, -9.8, 42.3], [-10.9, 40.0, -10.1, 40.9, -9.3, 41.7]], [-10.4, 41.0]);
            腕釧(bi, [[15.0, 45.2, 16.1, 45.7, 17.2, 45.3], [14.8, 46.1, 15.9, 46.6, 17.0, 46.2]], [15.9, 46.1]);
        });
    },
});
